import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useTheme } from '../context/ThemeContext';

function SunIcon() {
  return (
    <svg xmlns="http://www.w3.org/2000/svg" className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
      <path strokeLinecap="round" strokeLinejoin="round" d="M12 3v1m0 16v1m8.66-9h-1M4.34 12h-1m15.07-6.07-.71.71M6.34 17.66l-.71.71m12.73 0-.71-.71M6.34 6.34l-.71-.71M12 5a7 7 0 1 0 0 14A7 7 0 0 0 12 5z" />
    </svg>
  );
}

function MoonIcon() {
  return (
    <svg xmlns="http://www.w3.org/2000/svg" className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
      <path strokeLinecap="round" strokeLinejoin="round" d="M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z" />
    </svg>
  );
}

export default function Navbar() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const { isDark, toggleTheme } = useTheme();

  const handleLogout = () => { logout(); navigate('/login'); };

  return (
    <nav className="h-12 flex items-center justify-between px-4 bg-white border-b border-gray-200 dark:bg-gh-default dark:border-gh-border sticky top-0 z-50 flex-shrink-0">
      {/* Left: Brand */}
      <Link to="/dashboard" className="flex items-center gap-2 no-underline">
        <div className="w-6 h-6 rounded-lg bg-brand-blue flex items-center justify-center flex-shrink-0">
          <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
            <path d="M22 12h-4l-3 9L9 3l-3 9H2"/>
          </svg>
        </div>
        <span className="text-sm font-semibold text-gray-900 dark:text-gh-text">AvailAPI</span>
      </Link>

      {/* Right: Nav items */}
      <div className="flex items-center gap-2">
        {user && (
          <>
            <Link
              to={`/status/${user.slug}`}
              className="text-xs text-gray-500 hover:text-gray-900 dark:text-gh-muted dark:hover:text-gh-text px-3 py-1.5 rounded-lg hover:bg-gray-100 dark:hover:bg-gh-subtle transition-colors no-underline"
            >
              Status Page
            </Link>
            <div className="w-px h-4 bg-gray-200 dark:bg-gh-border" />
          </>
        )}

        {/* Theme toggle */}
        <button
          onClick={toggleTheme}
          className="p-1.5 rounded-lg text-gray-500 hover:text-gray-900 hover:bg-gray-100 dark:text-gh-muted dark:hover:text-gh-text dark:hover:bg-gh-subtle transition-colors"
          title={isDark ? 'Switch to light mode' : 'Switch to dark mode'}
        >
          {isDark ? <SunIcon /> : <MoonIcon />}
        </button>

        {user && (
          <>
            <div className="w-7 h-7 rounded-full bg-brand-blue dark:bg-gh-green flex items-center justify-center text-white text-xs font-semibold border border-gray-200 dark:border-gh-border flex-shrink-0" title={user.email}>
              {user.email?.[0]?.toUpperCase()}
            </div>
            <button
              onClick={handleLogout}
              className="text-xs text-gray-500 hover:text-gray-900 dark:text-gh-muted dark:hover:text-gh-text px-2 py-1 rounded transition-colors"
            >
              Sign out
            </button>
          </>
        )}
      </div>
    </nav>
  );
}
